# -*- coding: utf-8 -*-
import base64
import json
import os
import re

from flask import Flask, request, jsonify, abort
from flask_cors import CORS

from.database import db_session
from.database.models import Task, TaskStatus
from.utils import check_task_id, check_task_status

app = Flask(__name__)
CORS(app)
app.config.from_object(__name__)
app.config.from_envvar('APP_SETTINGS', silent=True)


@app.route('/tasks', methods=['GET'])
def get_tasks():
    tasks = Task.query.all()
    return jsonify([task.to_json() for task in tasks])


@app.route('/tasks/<task_id>', methods=['GET'])
def get_task_by_id(task_id):
    task = check_task_id(Task, task_id)
    return jsonify(task.to_json())


@app.route('/tasks', methods=['POST'])
def create_task():
    task_data = request.get_json()
    task = Task(**task_data)
    db_session.add(task)
    db_session.commit()
    return jsonify(task.to_json()), 201


@app.route('/tasks/<task_id>', methods=['PUT'])
def update_task_by_id(task_id):
    task = check_task_id(Task, task_id)
    task_data = request.get_json()
    task.update(**task_data)
    db_session.add(task)
    db_session.commit()
    return jsonify(task.to_json()), 201


@app.route('/tasks/<task_id>/status', methods=['PUT'])
def update_task_status_by_id(task_id):
    task = check_task_id(Task, task_id)
    task_data = request.get_json()
    task_status = check_task_status(task.status, task_data['status'])
    task.update(status=task_status)
    db_session.add(task)
    db_session.commit()
    return jsonify(task.to_json()), 201


@app.route('/tasks/<task_id>', methods=['DELETE'])
def delete_task_by_id(task_id):
    task = check_task_id(Task, task_id)
    db_session.delete(task)
    db_session.commit()
    return jsonify({'message': 'Task deleted'}), 204


@app.errorhandler(404)
def not_found(error):
    return jsonify({'message': 'Not found'}), 404


@app.errorhandler(400)
def bad_request(error):
    return jsonify({'message': 'Bad request'}), 400


@app.errorhandler(500)
def internal_server_error(error):
    return jsonify({'message': 'Internal server error'}), 500


